-- Decorative rendering rates + UK regional cost multipliers.
--
-- Every rate has: source_publisher, source_url, last_verified_at.
-- Rates are RANGES (low + high pence). Ranges wide enough to
-- protect trade quoting margin (see earlier brainstorm).
--
-- Excludes note on every row makes explicit what is NOT included —
-- scaffolding, beads, prep beyond basic, product brand premium, VAT.

-- ─── Regional multipliers (ONS Building Cost Index basis) ─────────
insert into hammerex_regional_cost_multipliers
  (region_slug, display_name, postcode_prefixes, multiplier, source_publisher, source_url, source_reference, applies_to_trades, notes)
values
  ('london-se',       'London + South East',       array['SW','SE','N','E','W','NW','EC','WC','KT','SM','CR','TW','BR','DA','UB','HA','EN','IG','RM'], 1.200, 'ONS Building Cost Index', 'https://www.ons.gov.uk/economy/inflationandpriceindices', 'BCI Q3 2026 regional table', array['all']::text[], 'London + immediate South East. Highest cost region — labour + delivery.'),
