  ('midlands',        'Midlands',                  array['B','CV','LE','NG','DE','ST','WV','DY','WS','TF','HR','WR','NN','LN'],                        0.950, 'ONS Building Cost Index', 'https://www.ons.gov.uk/economy/inflationandpriceindices', 'BCI Q3 2026 regional table', array['all']::text[], 'Birmingham, Coventry, Nottingham, Derby, Leicester.'),
  ('yorkshire',       'Yorkshire + Humber',        array['LS','S','DN','WF','HD','HG','HU','YO','BD','HX'],                                             0.900, 'ONS Building Cost Index', 'https://www.ons.gov.uk/economy/inflationandpriceindices', 'BCI Q3 2026 regional table', array['all']::text[], 'Leeds, Sheffield, Bradford, Hull.'),
  ('north-west',      'North West',                array['M','L','PR','BL','WA','WN','BB','CH','FY','LA','SK','OL','CW'],                              0.920, 'ONS Building Cost Index', 'https://www.ons.gov.uk/economy/inflationandpriceindices', 'BCI Q3 2026 regional table', array['all']::text[], 'Manchester, Liverpool, Lancashire, Preston.'),
