  ('wales',           'Wales',                     array['CF','SA','NP','LL','LD','SY'],                                                                0.900, 'ONS Building Cost Index', 'https://www.ons.gov.uk/economy/inflationandpriceindices', 'BCI Q3 2026 regional table', array['all']::text[], 'Cardiff, Swansea, Newport + rural Wales.'),
