on conflict (region_slug) do update set
  postcode_prefixes = excluded.postcode_prefixes,
  multiplier        = excluded.multiplier,
  source_url        = excluded.source_url,
  source_reference  = excluded.source_reference,
  last_verified_at  = excluded.last_verified_at,
  notes             = excluded.notes;

-- ─── Decorative rendering rate rows ───────────────────────────────
-- All from published UK trade sources. Ranges wide enough to
-- accommodate trade variation. Every row cites publisher + URL.
insert into hammerex_trade_rates
  (trade_slug, line_item_slug, display_name, description, unit, price_low_pence, price_high_pence, source_publisher, source_url, source_reference, applies_to_regions, excludes_notes, finish_slug, confidence)
